function create(svg: string, fileName: string) {
  const content = svg
    .replace(/width="\d+"/, "width={size}")
    .replace(/height="\d+"/, "height={size}")
    .replace(">", `{...props} ref={forwardedRef} >`)
    .replace(/<path(.+)fill=".+?"(.+)>/g, "<path$1fill={color}$2>")
    .replace(/<circle(.+)fill=".+?"(.+)>/g, "<circle$1fill={color}$2>")
    .replace(/stroke-width/g, "strokeWidth")
    .replace(/stroke-linecap/g, "strokeLinecap")
    .replace(/stroke-linejoin/g, "strokeLinejoin")
    .replace(/clip-rule/g, "clipRule")
    .replace(/fill-rule/g, "fillRule")
    .replace(/<path(.+)stroke=".+?"(.+)>/g, "<path$1stroke={color}$2>")
    .replace(/<circle(.+)stroke=".+?"(.+)>/g, "<circle$1stroke={color}$2>")
  const componentName = camelcase(fileName, { pascalCase: true, preserveConsecutiveUppercase: true })
  const previewSvg = npc.paste().replace(">", ' style="background:#fff">')
  const preview = Buffer.from(previewSvg).toString("base64")
  fs.writeFileSync(
    `./src/component/ui/icon/${fileName}.tsx`,
    componentTemplate.replace("%svg%", content).replace("%componentName%", componentName).replace("%preview%", preview),
  )
  const exportContent = `export * from "./${fileName}"\n`
  const fileContent = fs.readFileSync(`./src/component/ui/icon/index.ts`, "utf-8")
  if (!fileContent.includes(exportContent)) {
    fs.appendFileSync(`./src/component/ui/icon/index.ts`, exportContent)
  }
}

