function svg2tsx(svgStr: string, filename: string) {
  let svg = optimize(svgStr, {
    plugins: [
      {
        name: "preset-default",
        params: {
          overrides: {
            removeViewBox: false,
          },
        },
      },
    ],
  }).data
  const preview = btoa(svg.replace(">", ' style="background:#fff">'))
  svg = svg
    .replace(/width="\d+"/, "width={size}")
    .replace(/height="\d+"/, "height={size}")
    .replace(">", `{...props} ref={forwardedRef} >`)
    .replace(/stroke-width/g, "strokeWidth")
    .replace(/stroke-linecap/g, "strokeLinecap")
    .replace(/stroke-linejoin/g, "strokeLinejoin")
    .replace(/clip-rule/g, "clipRule")
    .replace(/fill-rule/g, "fillRule")
  return componentTemplate.replace("%svg%", svg).replaceAll("%componentName%", pascalCase(filename)).replace("%preview%", preview)
}

function create(svg: string, fileName: string) {
  const svgComponent = svg2tsx(svg, fileName)
  fs.writeFileSync(`./src/component/ui/icon/${fileName}.tsx`, svgComponent)
  const exportContent = `export * from "./${fileName}"\n`
  const fileContent = fs.readFileSync(`./src/component/ui/icon/index.ts`, "utf-8")
  if (!fileContent.includes(exportContent)) {
    fs.appendFileSync(`./src/component/ui/icon/index.ts`, exportContent)
  }
}

