async function formatContent(content: string): Promise<string> {
  const eslint = new ESLint({ fix: true })
  const results = await eslint.lintText(content, { filePath: "generatedRoutes.tsx" })
  return results[0]?.output || content
}

function convertArgs(args: string[]) {
  type Args = { default?: boolean; param?: string[] }
  const res: Args = {}
  args.forEach((m) => {
    if (m === "default") {
      res.default = true
    }
    if (m.startsWith("[")) {
      const key = m.slice(1, -1)
      if (!res.param) res.param = []
      res.param.push(":" + key)
    }
    if (m.startsWith("(")) {
      const key = m.slice(1, -1)
      if (!res.param) res.param = []
      res.param.push(":" + key + "?")
    }
  })
  return res
}

function conventionRouter(dir: string) {
  const pages = globSync(path.resolve(dir), /^index.*\.tsx$/)
  const $pages = Object.entries(pages)
  $pages.sort((a, b) => a[0].split("/").length - b[0].split("/").length)
  const routers: RouteObject[] = []
  const routeMap: RouteMap = {}

  $pages.forEach(([path, component]) => {
    const paths = path.split("/")
    const args = convertArgs(paths[paths.length - 1].split(".").slice(1, -1))
    const dirs = paths.slice(0, -1)
    const pathKey = dirs.join("/")
    const params = args.param
    const curPath = pathKey + (params ? `/${params.join("/")}` : "")
    const parent = dirs.slice(0, dirs.length - 1).join("/")
    routeMap[pathKey] = {
      id: pathKey,
      path: curPath,
      element: `/${dir}/${component}`,
      children: [],
    }
    if (dirs.length > 1 && routeMap[parent]) {
      routeMap[parent].children!.push({
        ...routeMap[pathKey],
        path: routeMap[pathKey].path.replace(parent, "").replace(/^\//, ""),
      })
      if (args.default) {
        routeMap[parent].children?.push({
          id: pathKey,
          index: true,
          path: "",
          element: `/${dir}/${component}`,
        })
      }
    } else {
      routers.push(routeMap[pathKey])
      if (args.default) {
        routers.push({
          id: pathKey,
          index: true,
          path: "",
          element: `/${dir}/${component}`,
        })
      }
    }
  })
  return routers
}

globSync = (dir: string, pattern: RegExp): GlobResult => {
  const result: GlobResult = {}

  const traverseDirectory = (currentDir: string) => {
    const files = fs.readdirSync(currentDir)

    files.forEach((file) => {
      const fullPath = path.join(currentDir, file)
      const stat = fs.statSync(fullPath)

      if (stat.isDirectory()) {
        traverseDirectory(fullPath)
      } else if (stat.isFile() && pattern.test(file)) {
        const relativePath = path.relative(dir, fullPath).replace(/\\/g, "/")
        result[relativePath] = path.relative(dir, fullPath).replace(/\\/g, "/")
      }
    })
  }

  traverseDirectory(dir)
  return result
}

function stringifyRoutes(routes: RouteObject[]): string {
  const routeStrings: string[] = []
  routes.forEach((route) => {
    const children = route.children ? stringifyRoutes(route.children) : "[]"
    const element =
      route.index === true
        ? `index: true, lazy: lazyLoad(import("..${route.element}"))`
        : `path: "${route.path}", id: "${route.id}", lazy: lazyLoad(import("..${route.element}")), children: ${children}`
    const routeString = `{
      ${element},
    }`
    routeStrings.push(routeString)
  })
  return `[${routeStrings.join(",")}]`
}

watchDir = (dir: string, initDir: string) => {
  const pagesDir = path.resolve(dir)
  fs.watch(pagesDir, { recursive: true }, (eventType, filename) => {
    if (filename && eventType === "rename") {
      generateRoutes(initDir)
    }
  })

  fs.readdir(pagesDir, { withFileTypes: true }, (err, entries) => {
    if (err) {
      console.error(`Failed to read directory ${pagesDir}:`, err)
      return
    }
    entries.forEach((entry) => {
      const fullPath = path.join(dir, entry.name)
      if (entry.isDirectory()) {
        watchDir(fullPath, initDir)
      }
    })
  })
}

generateRoutes = async (dir: string) => {
  const routes = conventionRouter(dir)
  const outputPath = path.resolve("src/generatedRoutes.tsx")
  const routerCode = `  /* eslint-disable @typescript-eslint/no-explicit-any */
                        import { DeferLoader, defineDeferLoader } from "./bc/defer-loader.tsx"
                        import { Text } from "./component/index.ts"
                        function lazyLoad(r: Promise<any>) {
                        return async () => {
                          const res = await r
                          const Component = res.default
                          if (!res.loader) return { Component, ErrorBoundary: res.ErrorBoundary }
                          const HydrateFallback = res.HydrateFallback
                          return {
                            element: (
                              <DeferLoader fallback={HydrateFallback ? <HydrateFallback /> : <Text t="text.loading" />}>
                                <Component />
                              </DeferLoader>
                            ),
                            loader: defineDeferLoader(res.loader),
                            ErrorBoundary: res.ErrorBoundary,
                          }
                        }
                      }
                      const routes = ${stringifyRoutes(routes)}
                      export default routes`
  const formattedRouterCode = await formatContent(routerCode)
  let currentContent = ""
  if (fs.existsSync(outputPath)) {
    currentContent = fs.readFileSync(outputPath, "utf-8")
  }
  if (currentContent !== formattedRouterCode) {
    fs.writeFileSync(outputPath, formattedRouterCode, "utf-8")
  }
}

function generateRoutesPlugin(dir: string): Plugin {
  return {
    name: "vite-plugin-generate-routes",
    configureServer() {
      watchDir(dir, dir)
    },
    buildStart: () => generateRoutes(dir),
  }
}

function mockPlugin(): PluginOption {
  const loadMockUrls = () => {
    if (fs.existsSync(".mock")) {
      return fs.readFileSync(".mock", { encoding: "utf-8" }).split("\n")
    }
    return []
  }
  const proxy = loadMockUrls().reduce(
    (a, b) => {
      a[`/api${b}`] = {
        target: ts + b,
        changeOrigin: true,
        rewrite: (path) => path.replace(`/api${b}`, ""),
      }
      return a
    },
    {} as Record<string, ProxyOptions>,
  )
  return {
    name: "mockWatch",
    enforce: "post",
    apply: "serve",
    config: (cfg) => {
      if (!cfg.server) return
      if (cfg.server.proxy) {
        cfg.server.proxy = {
          ...proxy,
          ...cfg.server.proxy,
        }
      } else {
        cfg.server.proxy = proxy
      }
    },
    // HMR
    handleHotUpdate({ file, server }) {
      if (file.endsWith(".mock")) {
        server.restart()
      }
    },
  }
}

