interface BatchAllProps extends Omit<BatchProps, "toggle" | "setIsBatch"> {
  itemKey: string
}

interface BatchNumProps {
  className?: string
  length: number
}

interface BatchItemProps extends Pick<BatchProps, "selected" | "toggle" | "maxSelection" | "setIsBatch"> {
  item: ListItem
  itemKey: string
}

function BatchAll({ allSelected, selected, setSelected, toggleAll, maxSelection, data, itemKey }: BatchAllProps) {
  const hasPartialSelection = useMemo(() => {
    return data.some((m) => selected.some((n) => n[itemKey] === m[itemKey]))
  }, [data, selected, itemKey])
  const handleToggleAll = () => {
    const tempTotal = [...new Set([...selected, ...data])]
    if (!allSelected && maxSelection) {
      if (selected.length < maxSelection) {
        if (tempTotal.length > maxSelection) {
          const remaining = maxSelection - selected.length
          const partialSelection = data.filter((m) => !selected.some((item) => item[itemKey] === m[itemKey])).slice(0, remaining)
          setSelected([...selected, ...partialSelection])
          toast({
            title: `Up to ${maxSelection} pictures can be selected simultaneously at most`,
          })
          return
        }
      } else if (selected.length === maxSelection && !hasPartialSelection) {
        toast({
          title: `Up to ${maxSelection} pictures can be selected simultaneously at most`,
        })
        return
      } else {
        setSelected(selected.filter((item) => !data.some((m) => item[itemKey] === m[itemKey])))
        return
      }
    }
    toggleAll()
  }
  return (
    <Checkbox
      className="h-6 w-6"
      checkSize={16}
      halfCheckClassName="h-3 w-3"
      onCheckedChange={handleToggleAll}
      checked={!allSelected && hasPartialSelection ? "indeterminate" : allSelected}
    >
      <Text t="select all" lg />
    </Checkbox>
  )
}

function BatchNum({ className, length = 0 }: BatchNumProps) {
  return <Text className={cn("text-sm", className)} t={`${length} selected`} />
}

function BatchCancel({ setIsBatch }: BatchCancelProps) {
  return (
    <Button
      variant={"outline"}
      onClick={() => {
        setIsBatch(false)
      }}
    >
      <Text className="text-xs cursor-pointer" t="Cancel" />
    </Button>
  )
}

function BatchItem({ item, selected, toggle, maxSelection, setIsBatch, itemKey }: BatchItemProps) {
  return (
    <Checkbox
      className="h-6 w-6 bg-accent-foreground"
      checkSize={16}
      checked={selected.some((m: ListItem) => m[itemKey] === item[itemKey])}
      onCheckedChange={(val) => {
        if (val && !selected.length) {
          setIsBatch(true)
        }
        if (!val && selected.length === 1) {
          setIsBatch(false)
        }
        if (maxSelection && selected.length >= maxSelection && val) {
          toast({ title: `Up to ${maxSelection} pictures can be selected simultaneously at most` })
          return
        }
        toggle(item)
      }}
    />
  )
}

