function Download({ selected, fileName, downloadUrl }: { selected: ListItem[]; fileName: string; downloadUrl: string }) {
  const [open, setOpen] = useState(false)
  const { toast } = useToast()

  const { run: handleDownload, cancel } = useRequest(
    async () => {
      const res = (await $axios.post(
        downloadUrl,
        {
          // 下载图组
          imageUrls: selected.map((m) => (!isEmpty(m.picList) ? m.picList : m.ossMainImageUrl || m.picUrl)).flat(),
          fileName,
        },
        {
          responseType: "blob",
        },
      )) as Blob
      return res
    },
    {
      manual: true,
      onSuccess: (res) => {
        toast({ title: t("text.success") })
        saveAs(res, `${fileName}.zip`)
        setOpen(false)
      },
      onError: (error) => {
        toast({ title: t("text.error"), description: error.message })
        setOpen(false)
      },
    },
  )

  const onClick = () => {
    setOpen(true)
    handleDownload()
  }

  const onCancel = () => {
    cancel()
    setOpen(false)
  }

  return (
    <>
      <Button variant={"accent"} onClick={onClick}>
        <Text t="Download" className="text-xs" />
      </Button>
      <Dialog open={open} onOpenChange={setOpen}>
        <DialogContent className="sm:max-w-[480px]">
          <DialogHeader>
            <DialogTitle>
              <Text t="Download" />
            </DialogTitle>
          </DialogHeader>
          <Spinner />
          <div className="flex items-center px-5">The pictures are being packed. Please wait for a moment</div>
          <div className="flex items-center justify-center gap-2 px-5">
            <Button variant={"accent"} onClick={() => onCancel()}>
              <Text t="Cancel" />
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </>
  )
}

function Batch({
  className,
  allSelected,
  selected,
  toggleAll,
  setIsBatch,
  setSelected,
  data,
  maxSelection,
  itemKey,
  fileName,
  downloadUrl,
}: BatchProps & { itemKey: string; fileName: string; downloadUrl: string }) {
  return (
    <div className={cn("w-full flex items-center", className)}>
      <div className="flex items-center gap-2">
        <BatchAll
          allSelected={allSelected}
          toggleAll={toggleAll}
          setSelected={setSelected}
          data={data}
          selected={selected}
          maxSelection={maxSelection}
          itemKey={itemKey}
        />
        <BatchNum length={selected.length} className="ml-1" />
      </div>
      <div className="flex-1" />
      <div className="flex items-center gap-2">
        <BatchCancel setIsBatch={setIsBatch} />
        <Download selected={selected} fileName={fileName} downloadUrl={downloadUrl} />
      </div>
