function Actions({ children }: ActionProps) {
  const [tooltipOpen, setTooltipOpen] = useState(false)
  const [dialogOpen, setDialogOpen] = useState(false)
  const { run: handleTooltipClose } = useDebounceFn(setTooltipOpen, { wait: 100 })

  const handleTooltip = (open: boolean) => {
    if (dialogOpen) return
    if (!open) {
      handleTooltipClose(false)
    } else {
      handleTooltipClose(true)
    }
  }

  const handleDialogOpenChange = (open: boolean) => {
    setDialogOpen(open)
    if (!open) {
      setTooltipOpen(false)
    }
  }

  return (
    <Tooltip.Provider delayDuration={100}>
      <Tooltip.Root open={tooltipOpen} onOpenChange={(open) => !dialogOpen && setTooltipOpen(open)}>
        <Tooltip.Trigger asChild>
          <div
            className="flex h-9 w-9 items-center justify-center rounded-md bg-background/70 cursor-pointer"
            onMouseEnter={() => handleTooltip(true)}
            onMouseLeave={() => handleTooltip(false)}
          >
            <EditIcon size={20} />
          </div>
        </Tooltip.Trigger>
        <Tooltip.Content
          className="min-w-28 rounded-none border-none bg-background p-0 text-foreground shadow-panel"
          align="end"
          side="bottom"
          sideOffset={6}
          onMouseEnter={() => handleTooltip(true)}
          onMouseLeave={() => handleTooltip(false)}
        >
          {React.Children.map(children, (child) =>
            React.cloneElement(child as React.ReactElement, {
              setTooltipOpen,
              setDialogOpen: handleDialogOpenChange,
            }),
          )}
        </Tooltip.Content>
      </Tooltip.Root>
    </Tooltip.Provider>
  )
}

