defineDeferLoader = <T extends LoaderFunction>(loader: T) => {
  return (args: LoaderFunctionArgs) => {
    return defer({
      data: loader(args),
    }) as ReturnType<typeof loader>
  }
}

function DeferLoader<T = unknown>({ children, fallback }: { children: React.ReactNode; fallback: React.ReactNode }) {
  const { data } = useLoaderData<{ data: T }>()
  return (
    <React.Suspense fallback={fallback}>
      <Await resolve={data}>{children}</Await>
    </React.Suspense>
  )
}

