function getDesignParams(labels?: string[][]) {
  const group = groupBy(labels || [], (m) => m[0])
  const designParams: { [key: string]: string[][] } = {}
  Object.keys(DesignQueryType).forEach((key) => {
    if (group[DesignQueryType[key as keyof typeof DesignQueryType]]?.length) {
      designParams[key.charAt(0).toLowerCase() + key.slice(1)] = group[DesignQueryType[key as keyof typeof DesignQueryType]].map(
        (m) => m.slice(1),
      )
    }
  })
  return designParams
}

