type FormRangeItemProps = {
  name: string
  children: React.ReactElement<React.ComponentProps<typeof Checkbox>, typeof Checkbox>
}

FormCheckItem: React.FC<FormRangeItemProps> = ({ children, name }) => {
  const { formData, setPartialFormData } = useFormContext()

  const Com = Slot as React.FC<React.ComponentProps<typeof Checkbox>>
  const props = children.props

  return (
    <Com
      checked={props.value ? formData[name] === props.value : formData[name] === true}
      onCheckedChange={(checked) => {
        setPartialFormData({
          [name]: checked ? ((props.value as string) ?? checked) : undefined,
        })
        props.onCheckedChange?.(checked)
      }}
    >
      {React.Children.only(children)}
    </Com>
  )
}

type FormRangeItemProps = {
  name: [string, string]
  children: React.ReactNode
}

FormRangeItem: React.FC<FormRangeItemProps> = ({ children, name }) => {
  const { formData, setPartialFormData } = useFormContext()
  const Com = Slot as React.FC<{
    value?: RangeValue
    children: React.ReactNode
    onValueChange?: (val: RangeValue) => void
  }>
  return (
    <Com
      value={[formData[name[0]], formData[name[1]]] as RangeValue}
      onValueChange={(val: RangeValue) => {
        setPartialFormData({
          [name[0]]: val[0],
          [name[1]]: val[1],
        })
      }}
    >
      {React.Children.only(children)}
    </Com>
  )
}

