function convertBaseDateWithDiff(value: string) {
  if (!value) return undefined
  const [baseDate, type, num] = value.split(",")
  if (type === "month") {
    return [
      format(startOfMonth(subMonths(baseDate, Number(num))), "yyyy-MM-dd"),
      format(endOfMonth(subMonths(baseDate, num === "0" ? 0 : 1)), "yyyy-MM-dd"),
    ]
  }
  return [
    format(startOfYear(subYears(baseDate, Number(num))), "yyyy-MM-dd"),
    format(endOfYear(subYears(baseDate, num === "0" ? 0 : 1)), "yyyy-MM-dd"),
  ]
}

