function GroupContent({ children }: { children?: React.ReactNode }) {
  const { expand } = useGroup()
  const $content = React.useRef<HTMLDivElement>(null)
  function collapseSection() {
    if (!$content.current) return
    const sectionHeight = $content.current.scrollHeight

    const elementTransition = $content.current.style.transition
    $content.current.style.transition = ""

    requestAnimationFrame(function () {
      if (!$content.current) return
      $content.current.style.height = sectionHeight + "px"
      $content.current.style.transition = elementTransition

      requestAnimationFrame(function () {
        if (!$content.current) return
        $content.current.style.height = 0 + "px"
      })
    })
  }

  function expandSection() {
    if (!$content.current) return
    const onTransitionend = () => {
      if (!$content.current) return
      $content.current.removeEventListener("transitionend", onTransitionend)
      $content.current.style.height = ""
    }
    const sectionHeight = $content.current.scrollHeight
    $content.current.style.height = sectionHeight + "px"
    $content.current.addEventListener("transitionend", onTransitionend)
  }

  useUpdateEffect(() => {
    if (expand) {
      expandSection()
    } else {
      collapseSection()
    }
  }, [expand])
  return (
    <div
      ref={$content}
      className="flex h-auto flex-wrap gap-2.5 overflow-hidden"
      style={{ transition: "height cubic-bezier(0.62, 0.29, 0.6, 1.26) .3s" }}
    >
      {children}
    </div>
  )
}

