interface FormProps<T> extends React.HTMLAttributes<HTMLDivElement> {
  value: T
  children: React.ReactNode
  asChild?: boolean
  onValueChange?: (value: T) => void
}

function Form<T extends Record<string, unknown>>({ children, asChild, onValueChange, value, ...rest }: FormProps<T>) {
  const Com = asChild ? Slot : "div"
  return (
    <FormContext.Provider
      value={{
        formData: value as Record<string, FormFieldValue>,
        setPartialFormData: (newValue) => {
          const data = { ...value, ...newValue } as T
          onValueChange?.(data)
        },
      }}
    >
      <Com {...rest}>{children}</Com>
    </FormContext.Provider>
  )
}

FormItem: React.FC<{ name: string; children: React.ReactNode; onValueChange?: (value: string) => void }> = ({
  children,
  onValueChange,
  name,
}) => {
  const [fieldValue, setFieldValue] = useFormField(name)
  const Com = Slot as React.FC<{
    name: string
    children: React.ReactNode
    value?: FormFieldValue
    onValueChange: (val: string) => void
  }>
  return (
    <Com
      name={name}
      value={fieldValue}
      onValueChange={(val: string) => {
        setFieldValue(val)
        onValueChange?.(val)
      }}
    >
      {React.Children.only(children)}
    </Com>
  )
}

interface FormFieldProps {
  name?: string
  value?: FormFieldValue
  onValueChange?: (val: FormFieldValue) => void
}

useFormField = <T = FormFieldValue>(name?: string) => {
  const { formData, setPartialFormData } = useFormContext()
  if (name === undefined) return [undefined, () => {}] as const
  return [formData[name] as T, (value: FormFieldValue) => setPartialFormData({ [name]: value })] as const
}

formFieldFactory = <T extends keyof React.JSX.IntrinsicElements | React.JSXElementConstructor<any>>(
  Component: T,
) => {
  return ({ name, value, onValueChange, ...rest }: React.ComponentProps<typeof Component> & { name: string }) => {
    const [fieldValue, setFieldValue] = useFormField<FormFieldValue>(name)
    return React.createElement(Component, {
      ...rest,
      name,
      value: value ?? fieldValue,
      onValueChange: (val: FormFieldValue) => {
        setFieldValue(val)
        onValueChange?.(val)
      },
    })
  }
}

