  active: boolean
}

KeepAlive: React.FC<KeepAliveProps> = ({ children, active }) => {
  useEffect(() => {
    if (active) {
      window.scrollTo(0, 0)
    }
  }, [active])

  return (
    <>
      <Suspense fallback={null}>
        <Wrapper active={active}>{children}</Wrapper>
      </Suspense>
      <Suspense fallback={null}>
        <Wrapper active={!active}>{children}</Wrapper>
      </Suspense>
    </>
  )
}

