interface MasonryData {
  width?: number
  height?: number
}

type MasonryItemProps<T = object> = React.HTMLAttributes<HTMLElement> & {
  asChild?: boolean
  children?: React.ReactNode
  data: T
} & Position

type MasonryMapProps<T extends MasonryData> = Omit<React.HTMLAttributes<HTMLElement>, "children"> & {
  /**
   * 包含宽高的数据
   */
  data: T[]
  /**
   * 最小列宽
   */
  columnWidth?: number
  /**
   * 间距
   */
  gap?: number
  /**
   * 卡片追加高度
   */
  addHeight?: number

  children: (params: { data: T; index: number } & Position) => React.ReactNode
}

MasonryLoading: React.FC<MasonryLoadingProps> = ({ asChild, ...rest }) => {
  const { loading } = React.useContext(MasonryContext)
  const Com = asChild ? Slot : Spinner
  if (!loading) return null
  return <Com {...rest} />
}

MasonryEmpty: React.FC<MasonryEmptyProps> = ({ asChild, className, ...rest }) => {
  const { loading, error, empty } = React.useContext(MasonryContext)
  const Com = asChild ? Slot : EmptyCard
  if (loading || error || !empty) return null
  return <Com className={cn("text-foreground", className)} {...rest} />
}

function MasonryError({ asChild, ...rest }: React.ComponentProps<typeof ErrorCard> & { asChild?: boolean }) {
  const { loading, error } = React.useContext(MasonryContext)
  if (loading || !error) return null
  const Com = asChild ? Slot : ErrorCard
  return <Com {...rest} />
}

function MasonryItem<T>({ w, h, x, y, asChild, className, children, style, ...rest }: MasonryItemProps<T>) {
  const Com = asChild ? Slot : "div"
  return (
    <Com
      className={cn("absolute transition", className)}
      style={{ ...style, width: w, height: h, transform: `translate(${x}px,${y}px)` }}
      {...rest}
    >
      {children}
    </Com>
  )
}

function usePositionData<T extends MasonryData>(
  data: T[],
  {
    columnWidth,
    gap,
    addHeight,
    containerTarget,
  }: { columnWidth: number; gap: number; addHeight: number; containerTarget: MutableRefObject<HTMLElement | null> },
) {
  const containerSize = useSize(containerTarget)
  const positionData = useMemo(() => {
    if (!containerSize?.width || !containerTarget?.current) return

    const columnCount = Math.floor((containerSize.width + gap) / (columnWidth + gap))
    const columns = Array.from({ length: columnCount }, () => 0)
    const calcColumnWidth = (containerSize.width + gap) / columnCount - gap
    return data.map((item, index) => {
      const height = min(columns)!
      const dataWidth = item.width ?? calcColumnWidth
      const dataHeight = item.height ?? calcColumnWidth
      const itemHeight = (calcColumnWidth / dataWidth) * dataHeight + addHeight
      const columnIndex = columns.indexOf(height)
      columns[columnIndex] += gap + itemHeight // 更新列高度
      containerTarget.current!.style.height = `${max(columns) ?? 0}px`

      return {
        index,
        x: (calcColumnWidth + gap) * columnIndex,
        y: height,
        w: calcColumnWidth,
        h: itemHeight,
        data: item,
      }
    })
  }, [containerSize?.width, gap, columnWidth, data, addHeight, containerTarget.current])
  return positionData
}

function MasonryViewBox<T extends MasonryData>({
  data,
  className,
  children,
  columnWidth = 255,
  gap = 16,
  addHeight = 0,
  overscan = 500, // 虚拟滚动不可见区域预渲染高度
  ...rest
}: MasonryMapProps<T> & { overscan?: number }) {
  const $ref = useRef<HTMLDivElement>(null)
  const positionData = usePositionData(data, { columnWidth, gap, addHeight, containerTarget: $ref })
  const renderData = useViewBox(positionData ?? [], { overscan, containerTarget: $ref })
  const { loading, error } = React.useContext(MasonryContext)
  if (loading || error) return null
  return (
    <div className={cn("relative", className)} {...rest}

renderData?.map((item) => children(item))}
    </div>
  )
}
function MasonryBase<T extends MasonryData>({
  data,
  className,
  children,
  columnWidth = 255,
  gap = 10,
  addHeight = 0,
  ...rest
}: MasonryMapProps<T>) {
  const $ref = useRef<HTMLDivElement>(null)
  const positionData = usePositionData(data, { columnWidth, addHeight, gap, containerTarget: $ref })
  const { loading } = React.useContext(MasonryContext)
  if (loading) return null
