type Position = {
  x: number
  y: number
  w: number
  h: number
}

type Option = {
  overscan?: number
  containerTarget?: MutableRefObject<Element | null>
  width?: number
  height?: number
}

function getClosestScrollingParent(element: HTMLElement) {
  // 如果元素为null或undefined，则返回null
  if (!element) {
    return null
  }
  let currentElement: HTMLElement | null = element
  // 遍历DOM树，从当前元素开始向上查找
  while (currentElement) {
    // 检查元素的overflow属性（包括overflowX和overflowY）
    const { overflow, overflowX, overflowY } = window.getComputedStyle(currentElement)
    // 如果任何一个overflow属性为auto、scroll或overlay，则返回该元素
    if (/(auto|scroll|overlay)/.test(overflow + overflowX + overflowY)) {
      return currentElement
    }
    // 否则，继续查找父元素
    currentElement = currentElement.parentElement
  }

  // 如果没有找到可滚动的父元素，则返回null
  return null
}

function getElementPosition(element: HTMLElement): { left: number; top: number } {
  let left = 0
  let top = 0
  let currentElement: HTMLElement | null = element

  // 累加offsetLeft和offsetTop直到达到最顶层的offsetParent
  while (currentElement) {
    left -= currentElement.offsetLeft
    top -= currentElement.offsetTop
    currentElement = currentElement.offsetParent as HTMLElement | null
  }
  // 加上窗口的滚动偏移量
  const scrollParent = getClosestScrollingParent(element)
  left += scrollParent?.scrollLeft ?? window.scrollX
  top += scrollParent?.scrollTop ?? window.scrollY
  return { left, top }
}

function useViewBox<T extends Position>(data: T[], { overscan = 0, containerTarget, width, height }: Option) {
  const $container = containerTarget?.current
  useEffect(() => {
    if (!$container) return
    const $scrollingContainer = getClosestScrollingParent($container as HTMLElement)

    const handleResize = () => {
      const { left, top } = getElementPosition($container as HTMLElement)
      setViewBox({
        x: left - overscan,
        y: top - overscan,
        w: width ?? window.innerWidth + overscan,
        h: height ?? window.innerHeight + overscan,
      })
    }
    let resizeAnimationFrameId: number | null = null
    const scheduleResize = () => {
      if (resizeAnimationFrameId !== null) {
        cancelAnimationFrame(resizeAnimationFrameId)
      }
      resizeAnimationFrameId = requestAnimationFrame(handleResize)
    }
    handleResize()
    window.addEventListener("resize", scheduleResize)
    ;($scrollingContainer ?? window).addEventListener("scroll", scheduleResize)
    return () => {
      window.removeEventListener("resize", scheduleResize)
      ;($scrollingContainer ?? window).removeEventListener("scroll", scheduleResize)
    }
  }, [overscan, $container])
  const [viewBox, setViewBox] = useState({ x: 0, y: 0, w: 0, h: 0 })
  return data.filter((m) => m.x > viewBox.x && m.y > viewBox.y && m.x < viewBox.x + viewBox.w && m.y < viewBox.h + viewBox.y)
}

