function getDateCalendarCells(date: Date = new Date()): Date[] {
  const daysInMonth = getDaysInMonth(date)
  const calendarCells: Date[] = []
  const startDateOfMonth = startOfMonth(date)
  const endDateOfMonth = endOfMonth(date)
  const startOfFirstWeek = startOfISOWeek(startDateOfMonth)
  const daysToFirstDay = differenceInDays(startDateOfMonth, startOfFirstWeek)

  for (let i = 1; i <= daysInMonth; i += 1) {
    calendarCells.push(setDate(date, i))
  }

  for (let i = daysToFirstDay - 1; i >= 0; i -= 1) {
    calendarCells.unshift(addDays(startOfFirstWeek, i))
  }

  for (let i = 1; i <= 42 - daysToFirstDay - daysInMonth; i += 1) {
    calendarCells.push(addDays(endDateOfMonth, i))
  }

  return calendarCells
}

function getDateCalendarRows(date: Date = new Date()): Date[][] {
  const cells = getDateCalendarCells(date)
  const rows: Date[][] = []

  for (let i = 0; i < cells.length; i += 7) {
    rows.push(cells.slice(i, i + 7))
  }

  return rows
}

function getMonthCalendarCells(date: Date = new Date()): Date[] {
  const calendarCells: Date[] = []
  const startDateOfYear = startOfYear(date)

  for (let i = 0; i < 12; i += 1) {
    calendarCells.push(addMonths(startDateOfYear, i))
  }

  return calendarCells
}

function getMonthCalendarRows(date: Date = new Date()): Date[][] {
  const cells = getMonthCalendarCells(date)
  const rows: Date[][] = []

  for (let i = 0; i < cells.length; i += 3) {
    rows.push(cells.slice(i, i + 3))
  }

  return rows
}

function getQuarterCalendarCells(date: Date = new Date()): Date[] {
  const calendarCells: Date[] = []
  const startDateOfYear = startOfYear(date)

  for (let i = 0; i < 4; i += 1) {
    calendarCells.push(addQuarters(startDateOfYear, i))
  }

  return calendarCells
}

function getQuarterCalendarRows(date: Date = new Date()): Date[][] {
  const cells = getQuarterCalendarCells(date)
  const rows: Date[][] = []

  for (let i = 0; i < cells.length; i += 2) {
    rows.push(cells.slice(i, i + 2))
  }

  return rows
}

function getYearCalendarCells(date: Date = new Date()): Date[] {
  const calendarCells: Date[] = []
  const startDateOfYear = startOfYear(date)
  const year = getYear(startDateOfYear)
  const start = setYear(startDateOfYear, year - (year % 10))
  for (let i = 0; i < 10; i += 1) {
    calendarCells.push(addYears(start, i))
  }
  // 添加上一页最后一年
  calendarCells.unshift(setYear(startDateOfYear, year - (year % 10) - 1))
  // 添加下一页第一年
  calendarCells.push(addYears(start, 10))
  return calendarCells
}

function getYearCalendarRows(date: Date = new Date()): Date[][] {
  const cells = getYearCalendarCells(date)
  const rows: Date[][] = []

  for (let i = 0; i < cells.length; i += 3) {
    rows.push(cells.slice(i, i + 3))
  }

  return rows
}

function toDate(value?: Date | string): Date | undefined {
  if (!value) {
    return undefined
  } else if (isDate(value)) {
    return value
  } else {
    return new Date(value)
  }
}

function turnDateCalendar(date: Date, isNextMonth: boolean): Date {
  if (getMonth(date) === 0 && !isNextMonth) {
    return setMonth(setYear(date, getYear(date) - 1), 11)
  }

  if (getMonth(date) === 11 && isNextMonth) {
    return setMonth(setYear(date, getYear(date) + 1), 0)
  }
  return addMonths(date, isNextMonth ? 1 : -1)
}

function turnMonthCalendar(date: Date, isNextYear: boolean): Date {
  return addYears(date, isNextYear ? 1 : -1)
}

function turnYearCalendar(date: Date, isNextDecade: boolean): Date {
  return addYears(date, isNextDecade ? 10 : -10)
}

function useTreeOptionSelection(options: Option[], defaultValue: string[][]) {
  const [selected, setSelected] = React.useState<string[][]>(defaultValue)
  const { forEach } = useTree(options)
  const selectedOptions = React.useMemo(() => {
    const result: Option[] = []
    forEach((node, link) => {
      selected.forEach((path) => {
        if (path.every((c, i) => path.length === link.length && link[i].value === c)) {
          result.push(node)
        }
      })
    })
    console.log("result", result)
    return result
  }, [options, selected])
  function selectState(item: Option) {
    if (selectedOptions.includes(item)) return true
    if (item.children && item.children.length > 0) {
      if (item.children.every((child) => selectState(child) === true)) {
        return true
      }
      if (item.children.some((child) => selectState(child))) {
        return "indeterminate"
      }
    }
    return false
  }
  function unselect(item: Option) {
    forEach((node, links) => {
      if (node === item) {
        setSelected((prev) => prev.filter((path) => path[links.length - 1] !== item.value))
        return false
      }
    })
  }
  function select(item: Option) {
    const newPaths = new Map<string, string[]>()
    forEach((node, all) => {
      if (!all.includes(item)) return
      if (node.children?.length) return
      const path = all.map((m) => m.value)
      newPaths.set(path.join(","), path)
    })

    if (newPaths.size > 0) {
      setSelected((prev) => {
        const existingPathKeys = new Set(prev.map((p) => p.join(",")))
        const mergedPaths = [...prev]
        newPaths.forEach((path, key) => {
          if (!existingPathKeys.has(key)) {
            mergedPaths.push(path)
          }
        })
        return mergedPaths
      })
    }
  }

  function selectAll() {
    const result: string[][] = []
    forEach((node, all) => {
      if (node.children && node.children?.length > 0) return
      const path = all.map((m) => m.value)
      result.push(path)
    })
    setSelected((prev) => prev.concat(result))
  }
  function unSelectAll() {
    setSelected([])
  }

  return {
    setSelected,
    selected,
    select,
    unselect,
    toggle: (item: Option) => {
      if (selectState(item) === true) unselect(item)
      else select(item)
    },
    selectAll,
    unSelectAll,
    selectState,
    selectedAllState: () => {
      if (selected.length === countLeaf({ children: options })) {
        return true
      } else if (selected.length) {
        return "indeterminate"
      } else return false
    },
  }
}

