function useLineBreak({
  lineWidth,
  lineNum,
  childrenWidth = [],
}: {
  lineWidth: number
  lineNum: number
  childrenWidth: number[]
}) {
  const [lineBreak, setLineBreak] = useState(false)
  const [breakNum, setBreakNum] = useState<number>()

  const handleResize = () => {
    let _lineBreak = false
    let _breakNum = undefined
    let lineLength = lineWidth
    let length = 0
    let line = 1
    for (let i = 0; i < childrenWidth.length; i++) {
      if (_lineBreak) {
        break
      }
      length = length + childrenWidth[i]

      for (let j = 1; j <= lineNum; j++) {
        if (length > lineLength && line === j) {
          if (j === lineNum) {
            _lineBreak = true
            _breakNum = i
            break
          } else {
            length = lineLength + childrenWidth[i]
            lineLength = lineWidth * lineNum
            line += 1
          }
        }
      }
    }
    setBreakNum(_breakNum)
    setLineBreak(_lineBreak)
  }
  const handleResizeRef = useRef(handleResize)

  useEffect(() => {
    handleResizeRef.current = handleResize
  }, [lineWidth, lineNum, childrenWidth])

  useEffect(() => {
    const onResize = () => handleResizeRef.current()
    onResize()
    window.addEventListener("resize", onResize)

    return () => {
      window.removeEventListener("resize", onResize)
    }
  }, [lineWidth, lineNum, childrenWidth])

  return { lineBreak, breakNum }
}

