function useLogin() {
  const location = useLocation()
  const mInfo = qs.parse(location.search.slice(1))
  const [userInfo, setUserInfo] = useUserInfo()

  const [token, setToken] = useToken()

  const { run: login } = useRequest(() => serviceMicrosoftAuthLogin({ authorizationCode: mInfo.code as string }), {
    manual: true,
    ready: !!mInfo.code && !token,
    refreshDeps: [mInfo.code],
    onSuccess(data) {
      setUserInfo(data)
      setToken(data?.token ?? "")
      history.replaceState(null, "", location.pathname)
    },
    onError(err) {
      toast({
        title: t("text.error"),
        description: err.message,
      })
    },
  })

  const { runAsync: localLogin } = useRequest((email: string) => serviceMicrosoftAuthQuickLogin({ email }), {
    manual: true,
  })

  const { runAsync: _logout } = useRequest(() => serviceMicrosoftAuthLogout({}), {
    manual: true,
  })

  if (mInfo.error) {
    toast({
      title: t("text.error"),
      description: mInfo.error_description as string,
    })
  }
  const logout = async () => {
    await _logout()
    setToken("")
    setUserInfo({})
  }
  return { mInfo, userInfo, login, logout, localLogin }
}

