type Option<V> = {
  value: V
  disabled?: boolean
}

function useSelections<V, T extends Option<V>>(opts: T[], defaultSelected?: V[]) {
  const options = opts.filter((opt) => !opt.disabled)
  const [selected, setSelected] = React.useState(defaultSelected ?? [])
  const select = (item: V) => setSelected([...selected, item])
  const isSelected = (item: V) => selected.includes(item)
  const unSelect = (item: V) => setSelected(selected.filter((i) => i !== item))
  const selectAll = () => setSelected(options.map((opt) => opt.value))
  const unSelectAll = () => setSelected([])
  const allSelected = options.every((opt) => selected.includes(opt.value))

  useDeepCompareEffect(() => {
    setSelected(defaultSelected ?? [])
  }, [defaultSelected])

  return {
    selected: selected as V[],
    noneSelected: !selected?.length,
    allSelected,
    partiallySelected:
      options.some((opt) => selected.includes(opt.value)) && !options.every((opt) => selected.includes(opt.value)),
    setSelected,
    isSelected,
    select,
    unSelect,
    toggle: (item: V) => {
      if (isSelected(item)) unSelect(item)
      else select(item)
    },
    selectAll,
    unSelectAll,
    toggleAll: () => {
      if (allSelected) unSelectAll()
      else selectAll()
    },
    selectedOptions: options.filter((opt) => selected.includes(opt.value)),
  }
}

