function traverseTree<T extends Tree>(tree: T[], callback: (item: T, parents: T[]) => false | void, parents: T[] = []) {
  for (let i = 0; i < tree.length; i++) {
    const node = tree[i]
    // 处理当前节点
    const next = callback(node, parents)
    if (next === false) return
    // 如果当前节点有子节点，则递归遍历子节点
    if (node.children && node.children.length > 0) {
      traverseTree(node.children as T[], callback, [...parents, node])
    }
  }
}

function countLeaf<T extends Tree>(tree: T): number {
  let count = 0
  traverseTree([tree], (node) => {
    if (!node.children || node.children.length === 0) {
      count++
    }
  })
  return count
}

function useTree<T extends Tree>(tree: T[]) {
  return {
    /**
     * 过滤树形结构，返回符合条件的节点数组
     *
     * @param fn 过滤函数，接收当前节点和当前节点的父节点列表（包含当前节点），返回布尔值
     * @returns 符合过滤条件的节点数组
     */
    filter(fn: (node: T, link: T[]) => boolean): T[] {
      const result: T[] = []
      traverseTree(tree, (node, parents) => {
        if (fn(node, [...parents, node])) {
          result.push(node)
        }
      })
      return result
    },

    /**
     * 遍历树结构，对树中每个节点执行给定函数，判断是否都满足条件
     *
     * @param fn 回调函数，参数为节点和当前节点的父节点列表（包含当前节点），返回值为布尔值
     * @returns 若所有节点都满足条件，则返回true，否则返回false
     */
    every(fn: (node: T, link: T[]) => boolean): boolean {
      let result = true
      traverseTree(tree, (node, parents) => {
        if (!fn(node, [...parents, node])) {
          result = false
          return false
        }
      })
      return result
    },
    /**
     * 判断树中是否存在满足条件的节点
     *
     * @param {(node:T, link:T[]) => boolean} fn 回调函数，用于判断节点是否满足条件
     * @param fn.node 当前遍历到的节点
     * @param fn.link 当前节点的父节点列表（包含当前节点）
     * @returns 若存在满足条件的节点则返回true，否则返回false
     */
    some(fn: (node: T, link: T[]) => boolean): boolean {
      let result = false
      traverseTree(tree, (node, parents) => {
        if (fn(node, [...parents, node])) {
          result = true
          return false
        }
      })
      return result
    },
    /**
     * 查找符合条件的节点
     *
     * @param fn 判断节点是否符合条件的函数，参数为当前节点及其父节点数组（包含当前节点）
     * @returns 符合条件的节点，若未找到则返回 undefined
     */
    find(fn: (node: T, link: T[]) => boolean): T | undefined {
      let result: T | undefined
      traverseTree(tree, (node, parents) => {
        if (fn(node, [...parents, node])) {
          result = node
          return false
        }
      })
      return result
    },
    findPath(fn: (node: T, link: T[]) => boolean): T[] | undefined {
      let result: T[] | undefined
      traverseTree(tree, (node, parents) => {
        if (fn(node, [...parents, node])) {
          result = [...parents, node]
          return false
        }
      })
      return result
    },
    /**
     * 遍历树形结构，对每个节点执行回调函数
     *
     * @param fn 回调函数，接收两个参数，当前节点node和该节点所有父节点的数组（包含当前节点）link
     */
    forEach(fn: (node: T, link: T[]) => void) {
      traverseTree(tree, (node, parents) => {
        fn(node, [...parents, node])
      })
    },
    /**
     * 遍历树形结构，对每个节点执行给定的函数，并返回执行结果组成的数组
     *
     * @param fn 对树中每个节点执行的函数，接收当前节点和父节点链表（包含当前节点）作为参数，返回任意类型的值
     * @returns 返回一个数组，包含树中每个节点执行函数后返回的结果
     */
    map<V>(fn: (node: T, link: T[]) => V): V[] {
      const result: V[] = []
      traverseTree(tree, (node, parents) => {
        result.push(fn(node, [...parents, node]))
      })
      return result
    },

    reduce<V>(fn: (prev: V, node: T, link: T[]) => V, initialValue?: V): V {
      let result: V = initialValue as V
      traverseTree(tree, (node, parents) => {
        result = fn(result!, node, [...parents, node])
      })
      return result!
    },
  }
}

