interface Options {
  navigateMode?: "push" | "replace"
  parseOptions?: qs.IParseOptions
  stringifyOptions?: qs.IStringifyOptions
}

useUrlState = <S>(initialState?: S | (() => S), options?: Options) => {
  const { navigateMode = "push", parseOptions, stringifyOptions } = options || {}
  const location = useLocation()
  // react-router v6
  const navigate = useNavigate()
  const update = useUpdate()

  const initialStateRef = useRef(typeof initialState === "function" ? (initialState as () => S)() : initialState || ({} as S))

  const queryFromUrl = useMemo(() => {
    return qs.parse(location.search.slice(1), { ...baseParseConfig, ...parseOptions })
  }, [location.search])

  const targetQuery = useMemo(() => ({ ...initialStateRef.current, ...queryFromUrl }), [queryFromUrl])

  const setState = (s: React.SetStateAction<S>) => {
    const newQuery = typeof s === "function" ? (s as (prevState: S) => S)(targetQuery) : s
    // 1. 如果 setState 后，search 没变化，就需要 update 来触发一次更新。比如 demo1 直接点击 clear，就需要 update 来触发更新。
    // 2. update 和 history 的更新会合并，不会造成多次更新
    update()
    if (navigate) {
      navigate(
        {
          hash: location.hash,
          search: qs.stringify({ ...queryFromUrl, ...newQuery }, { ...baseStringifyConfig, ...stringifyOptions }) || "?",
        },
        {
          replace: navigateMode === "replace",
          state: location.state,
        },
      )
    }
  }

  return [targetQuery, useMemoizedFn(setState)] as const
}

