function capitalizeFirstLetter(word: string) {
  return word.charAt(0).toUpperCase() + word.slice(1)
}

function convertStartAndEnd<T = string | undefined>(field: string, value: T[] | undefined) {
  return { ["start" + capitalizeFirstLetter(field)]: value?.[0], ["end" + capitalizeFirstLetter(field)]: value?.[1] }
}

function convertMinAndMax<T = string | undefined>(field: string, value: T[] | undefined) {
  return { ["min" + capitalizeFirstLetter(field)]: value?.[0], ["max" + capitalizeFirstLetter(field)]: value?.[1] }
}

function convertMinAndMaxTiktok<T = string | undefined>(field: string, value: T[] | undefined) {
  return { [field + "Min"]: value?.[0], [field + "Max"]: value?.[1] }
}

function convertIndustryCategories({ industry, categories }: { industry?: string; categories?: string[][] }) {
  if (!categories) {
    return undefined
  }
  if (!industry) {
    return categories
  }
  return categories.map((c) => [industry, ...c])
}

