function formatDuration(s = 0, formatStr = "HH:mm:ss") {
  const HH = secondsToHours(s).toFixed(0).padStart(2, "0")
  const mm = secondsToMinutes(s).toFixed(0).padStart(2, "0")
  const ss = Math.floor(s % 60)
    .toFixed(0)
    .padStart(2, "0")

  return formatStr.replace("HH", HH).replace("mm", mm).replace("ss", ss)
}

function formatDateDisplay(value?: string, options = RECENT_DATE_OPTIONS) {
  if (!value) return null
  const item = options.find((o) => o.value === value)
  if (item) {
    return item.label
  }
  const arrayVal = value.split(",") || []
  if (arrayVal[0] === arrayVal[1]) {
    return toLocale(arrayVal[0], "yyyy-MM-dd")
  } else {
    return toLocale(arrayVal[0], "yyyy-MM-dd") + " - " + toLocale(arrayVal[1], "yyyy-MM-dd")
  }
}

