function saveAsExcel({ data, fileName }: { fileName: string; data: TableProps[] }) {
  return new Promise<void>((resolve) => {
    const workbook = new ExcelJs.Workbook()
    data.forEach((f) => {
      const worksheet = workbook.addWorksheet(f.sheetName)
      worksheet.properties.defaultColWidth = 40
      worksheet.columns = f.columns
      worksheet.addRows(f.rowData)
      worksheet.columns.forEach((column) => {
        let maxLength = 0
        if (column.eachCell) {
          column.eachCell({ includeEmpty: true }, (cell) => {
            const columnLength = cell.value ? cell.value.toString().length : 10
            if (columnLength > maxLength) {
              maxLength = columnLength
            }
          })
        }
        column.width = maxLength < 10 ? 10 : maxLength
      })
    })
    workbook.xlsx.writeBuffer().then((buffer) => {
      buffer2File(buffer, fileName)
      resolve()
    })
  })
}

