function formatPercent(value: number, fractionDigits = 2) {
  if (isNumber(value)) {
    return `${(value * 100).toFixed(fractionDigits)}%`
  } else {
    return value
  }
}

function formatNumber(
  value: number | undefined | null,
  fractionDigits = 2,
  format: [number, string][] = [
    [1_000_000, "m"],
    [1_000, "k"],
  ],
) {
  if (value === undefined || value === null) {
    return ["-", null]
  }
  for (const option of format) {
    if (Math.abs(value) >= option[0]) {
      const r = Math.round((value / option[0]) * 10 ** fractionDigits) / 10 ** fractionDigits
      const s = r.toLocaleString()
      return [s, option[1]]
    }
  }
  const s = Number(value.toFixed(fractionDigits)).toLocaleString()
  return [s, null]
}

async function getBase64Image(url: string): Promise<string> {
  return new Promise((resolve, reject) => {
    const canvas = document.createElement("canvas")
    const ctx = canvas.getContext("2d")
    const img = new Image()
    img.crossOrigin = "Anonymous"
    img.addEventListener("load", () => {
      canvas.width = img.naturalWidth
      canvas.height = img.naturalHeight
      ctx!.drawImage(img, 0, 0)
      resolve(canvas.toDataURL("image/jpeg"))
      canvas.remove()
      img.remove()
    })
    img.addEventListener("error", () => reject(new Error("图片加载失败")))
    img.src = url
  })
}

async function downloadOssImageByUrl(url: string, name?: string) {
  const fileName = name || url.split("/").pop() || "image.png"
  const userAgent = navigator.userAgent.toLocaleLowerCase()
  const a = document.createElement("a")
  a.download = fileName

  if (userAgent.match(/tencenttraveler/) || userAgent.match(/qqbrowse/)) {
    a.href = `${url
      .replace("zhiyi-web.oss-cn-hangzhou.aliyuncs.com", "zhiyi-web.zhiyitech.cn")
      .replace(
        "zhiyi-image.oss-cn-hangzhou.aliyuncs.com",
        "zhiyi-image-cdn.zhiyitech.cn",
      )}?response-content-type=application/octet-stream`
  } else {
    a.href = await getBase64Image(`${url}?_${Date.now()}`)
  }
  a.click()
  URL.revokeObjectURL(a.href)
}

function formdataFile(url: string, file: File) {
  const config = { headers: { "Content-Type": "multipart/form-data" } }
  const formData = new FormData()
  formData.append("file", file)
  return $axios.post(url, formData, config)
}

function cdnUrl(url: string | undefined | null): string | undefined {
  if (url) return url.replace("zhiyi-image.oss-cn-hangzhou.aliyuncs.com", "lf-cdn.zhiyitech.cn")
}

function formatNumText(
  start: number | string,
  end: number | string,
  options: { label: string | null | undefined; value: string }[],
): string {
  if (!start && start !== 0 && !end && end !== 0) {
    return ""
  }
  const item = options.find((o) => o.value === (start || "") + "-" + (end || ""))
  if (item) {
    return item.label || ""
  }

  if (start === end) {
    return start + ""
  }

  if (start && !end && end !== 0) {
    return ">" + Number(start).toLocaleString()
  }

  if (end && !start && start !== 0) {
    return "<" + Number(end).toLocaleString()
  }
  return Number(start).toLocaleString() + "-" + Number(end).toLocaleString()
}

