function AddLanguage() {
  const { addLanguage } = useDictionary()
  const [language, setLanguage] = useState("")

  return (
    <Textbox value={language} onValueChange={(v) => setLanguage(v)} className="w-48">
      <TextboxSuffix>
        <Button
          variant="ghost"
          size="s"
          onClick={() => {
            addLanguage(language)
            setLanguage("")
          }}
        >
          新增语言
        </Button>
      </TextboxSuffix>
    </Textbox>
  )
}

useDictionary = (filter: DictionaryFIlter = {}) => {
  const { toast } = useToast()
  const [languages, setLanguages] = useSessionStorageState<TranslateWebViewRespDto["lang"]>("i18nLanguages", {
    defaultValue: [],
    listenStorageChange: true,
  })
  const [data, setData] = useState<TranslateWebViewRespDto["dict"]>()
  /**为什么要和其他filter分开写？
   * 为了避免直接在搜索结果中修改内容产生跳动*/

  const { run: fetch, loading } = useRequest(serviceTranslateExcludeListKeyDict, {
    onSuccess(res) {
      setLanguages(res.lang || [])
      if (!res.dict?.length) {
        setData([{ dict: {}, newId: uniqueId(), isNew: true }])
      } else {
        setData(res.dict)
      }
    },
    onError(err) {
      toast({
        title: "获取数据错误",
        description: err.message,
      })
    },
  })

  const { run: save } = useRequest(
    () => {
      const dict = data?.filter((m) => !!m.key && (m.isNew || m.isModified))
      return serviceTranslateBatchSave({ dict })
    },
    {
      manual: true,
      onSuccess() {
        toast({
          title: "保存成功",
        })
        fetch()
      },
      onError(err) {
        toast({
          title: "保存失败",
          description: err.message,
        })
      },
    },
  )

  const { run: del } = useRequest(
    (item) => {
      if (item.isNew) {
        return Promise.resolve(-1)
      }
      return serviceTranslateBatchDelete({ keyList: [item.key] })
    },
    {
      manual: true,
      onSuccess(_, [item]) {
        const tempData = data || []
        const index = tempData.findIndex((m) => (m.key && m.key === item.key) || (m.newId && m.newId === item.newId))
        tempData.splice(index, 1)
        setData([...tempData])
        toast({
          title: "删除成功",
          description: "已删除" + (item.key || ""),
        })
      },
      onError(err) {
        toast({
          title: "删除失败",
          description: err.message,
        })
      },
    },
  )

  const updateDataItem = (item: TranslateWebViewDto) => {
    const tempData = data || []
    const index = tempData.findIndex((m) => (m.newId ? m.newId === item.newId : m.key && m.key === item.key))
    if (index > -1) {
      tempData[index] = { ...item, isModified: !item.isNew }
    } else {
      tempData.unshift({ dict: {}, namespace: "common", ...item, isNew: true, newId: uniqueId() })
    }
    setData([...tempData])
  }

  const addLanguage = (language: string) => {
    if (!language.trim()) {
      toast({
        title: "添加语言错误",
        description: "不能为空",
        variant: "destructive",
      })
      return
    }
    setLanguages([...(languages || []), language])
  }

  useEffect(() => {
    if (!data?.length) {
      return
    }
    const reg = new RegExp(filter.search || "", "i")
    for (let i = 0; i < data.length; i++) {
      if (
        reg.test(data[i].key || "") ||
        reg.test(data[i].namespace || "") ||
        reg.test(data[i].description || "") ||
        Object.values(data[i].dict || {}).some((n) => reg.test((n as string | undefined) || ""))
      ) {
        data[i].isSearch = true
      } else {
        data[i].isSearch = false
      }
      if (filter.hasEmptyDict && languages?.every((n) => data[i].dict?.[n])) {
        data[i].hasEmptyDict = false
      } else {
        data[i].hasEmptyDict = true
      }

      if (filter.isKeyEmpty && data[i].key?.trim()) {
        data[i].isKeyEmpty = false
      } else {
        data[i].isKeyEmpty = true
      }
    }

    setData([...data])
  }, [filter.search, filter.hasEmptyDict, filter.isKeyEmpty])

  const filterData = useMemo(() => {
    return data?.filter((m) => {
      let flag = true
      if (m.isSearch !== undefined && !m.isSearch) {
        flag = false
      }
      if (filter.isNew && !m.isNew) {
        flag = false
      }
      if (filter.isModified && !m.isModified) {
        flag = false
      }
      if (filter.hasEmptyDict && m.hasEmptyDict !== undefined && !m.hasEmptyDict) {
        flag = false
      }
      if (filter.isKeyEmpty && m.isKeyEmpty !== undefined && !m.isKeyEmpty) {
        flag = false
      }

      return flag
    })
  }, [data, filter.isModified, filter.isNew, filter.hasEmptyDict, filter.isKeyEmpty])

  return {
    languages,
    data,
    filterData,
    loading,
    updateDataItem,
    save,
    del,
    addLanguage,
  }
}

