function App() {
  const location = useLocation()

  useEffect(() => {
    const currentPath = location.pathname
    const storedCurrentPath = localStorage.getItem("currentPath")
    // 检查是否是从父路径重定向到子路径的情况
    const isRedirectToSubPath = storedCurrentPath && currentPath.startsWith(storedCurrentPath + "/")

    // 检查当前路径和存储的路径是否都包含 detail
    const currentHasDetail = currentPath.includes("/detail")
    const storedHasDetail = storedCurrentPath && storedCurrentPath.includes("/detail/")

    if (currentHasDetail) {
      if (!storedHasDetail && storedCurrentPath) {
        // 如果当前路径包含 detail，但存储的路径不包含 detail
        // 说明用户刚从其他页面进入 detail 页面，记录来源页面
        const fullPreviousUrl = `${window.location.protocol}//${window.location.host}${storedCurrentPath}`
        localStorage.setItem("previousPath", fullPreviousUrl)
        localStorage.setItem("detailSourcePath", fullPreviousUrl)
      } else if (storedHasDetail) {
        // 如果当前路径和存储的路径都包含 detail
        // 说明用户在 detail 页面内部跳转，使用之前保存的来源页面
        const detailSourcePath = localStorage.getItem("detailSourcePath")
        if (detailSourcePath) {
          localStorage.setItem("previousPath", detailSourcePath)
        }
      }
    } else if (storedCurrentPath && storedCurrentPath !== currentPath && !isRedirectToSubPath) {
      // 正常情况下的处理逻辑（非 detail 页面）
      const fullPreviousUrl = `${window.location.protocol}//${window.location.host}${storedCurrentPath}`
      localStorage.setItem("previousPath", fullPreviousUrl)
    }

    // 更新当前路径
    localStorage.setItem("currentPath", currentPath)
  }, [location.pathname, location.search, location.hash])

  return (
    <>
      <ImageListProvider>
        <Outlet />
      </ImageListProvider>
      <Toaster />
    </>
  )
}

