useCopy = () => {
  const [copied, setCopy] = useState(false)
  const copy = (text: string) => {
    navigator.clipboard.writeText(text)
    setCopy(true)
    setTimeout(() => {
      setCopy(false)
    }, 1000)
  }
  return { copy, copied }
}

function IconContainer({ Icon, name }: { Icon: typeof icons.AiIcon; name: string }) {
  const { copy, copied } = useCopy()
  return (
    <div className="mr-2 flex flex-col items-center justify-center gap-2 border p-4">
      <Icon size={32} />
      <span className="text-xs text-muted-foreground">{name}</span>
      <Button variant={"link"} className="h-auto p-0 text-sm" onClick={() => copy(`<${name} size={24} />`)}>
        {copied ? "copied" : "copy"}
      </Button>
    </div>
  )
}

