function InstagramPost() {
  const { id } = useParams()
  const { data: detail = {}, loading } = useRequest(() => serviceFashionInsBlogDetail({ id: id! }), { refreshDeps: [id] })
  const { data } = useImageList()
  const { preId, nextId } = useMemo(() => {
    const postList: ImageBusEntityVoInsBlogDataVo[] = (data as ImageBusEntityVoInsBlogDataVo[]) || []
    const currentIndex = postList.findIndex((m) => m.entityId === id)
    const preId = currentIndex > 0 ? postList[currentIndex - 1].entityId : undefined
    const nextId = currentIndex < postList.length - 1 ? postList[currentIndex + 1].entityId : undefined
    return { preId, nextId }
  }, [data, id])
  const sortImagesByPicList = (detail: ImageBusEntityVoInsBlogDataVo) => {
    const picUrlToImage = detail.images?.reduce(
      (acc: UnionImageVo, image: UnionImageVo) => {
        acc[image.picUrl || ""] = image
        return acc
      },
      {} as Record<string, (typeof detail.images)[number]>,
    )

    const sortedImages = detail.picList?.map((picUrl) => picUrlToImage?.[picUrl])

    return sortedImages
  }

  const { addBrowsingHistory } = useBrowsingHistory()
  useEffect(() => {
    window.scrollTo(0, 0)
    addBrowsingHistory({ entityId: id, entityType: "INS_BLOG" })
  }, [id])

  return (
    <RecoilRoot>
      <InstagramPostContext.Provider value={{ detail, images: sortImagesByPicList(detail), loading }}>
        <div className="mb-3">
          <GoBack />
        </div>
        <Panel.Root className="pt-3">
          <Panel.Content className="relative">
            <Outlet />
            {!loading && <Link preId={preId} nextId={nextId} />}
          </Panel.Content>
        </Panel.Root>
      </InstagramPostContext.Provider>
    </RecoilRoot>
  )
}

function Link({ preId, nextId }: { preId?: string; nextId?: string }) {
  const { id } = useParams()
  const [, setInsPostParams] = useInstagramPostParams()
  const navigator = useNavigate()
  useEffect(() => {
    setInsPostParams((pre) => ({ ...pre, currentIndex: 0, currentTab: "" }))
  }, [id, setInsPostParams])
  return (
    <NavArrow
      onViewPre={() => {
        navigator({ pathname: `/work-stage/detail/instagram-post/${preId}` }, { replace: true })
      }}
      onViewNext={() => {
        navigator({ pathname: `/work-stage/detail/instagram-post/${nextId}` }, { replace: true })
      }}
      preVisible={!!preId}
      nextVisible={!!nextId}
    />
  )
}

