function DashboardDetail() {
  const $pdf = useRef<HTMLDivElement>(null)
  const [params] = useDashboardParams()
  const [query, setQuery] = useUrlState<GoogleSearchKeywordOverviewRequest>(
    {
      startDate: format(startOfMonth(subMonths(new Date(), 36)), "yyyy-MM-dd"),
      endDate: format(endOfMonth(subMonths(new Date(), 1)), "yyyy-MM-dd"),
    },
    { navigateMode: "replace" },
  )
  const { data, loading } = useRequest(
    () =>
      serviceSearchKeyOverview({
        ...query,
        ...convertTrendCategory(params.trendCategory),
      } as GoogleSearchKeywordTrendDetailRequest),
    {
      refreshDeps: [query],
    },
  )

  const { data: trendData, loading: trendLoading } = useRequest(
    () =>
      serviceSearchKeyTrendDataDetail({
        ...query,
        ...convertTrendCategory(params.trendCategory),
        startDate: format(startOfMonth(subMonths(new Date(), 24)), "yyyy-MM-dd"),
        endDate: format(endOfMonth(subMonths(new Date(), 1)), "yyyy-MM-dd"),
      } as GoogleSearchKeywordTrendDetailRequest),
    {
      refreshDeps: [JSON.stringify({ ...query, startDate: undefined, endDate: undefined })],
    },
  )

  const toPdf = async () => {
    if (!$pdf.current) return
    try {
      const width = $pdf.current.clientWidth
      const height = $pdf.current.clientHeight
      const dataUrl = await toJpeg($pdf.current, { quality: 1 })
      const isLandscape = width > height
      const doc = new jsPDF({
        unit: "px",
        orientation: isLandscape ? "landscape" : "portrait",
        format: [width / 2, height / 2],
      })
      doc.addImage(dataUrl, "JPEG", 0, 0, width / 2, height / 2)
      doc.save(`${query?.keyword}_${format(new Date(), "yyyy-MM-dd")}.pdf`)
    } catch (err) {
      console.error(err)
    }
  }

  return (
    <div className="flex flex-col gap-2.5">
      <header className="flex items-center rounded-lg bg-background px-7.5 py-5">
        <BackLink fallback="/work-stage/dashboard/" className="inline-flex cursor-pointer gap-2">
          <LeftIcon size={24} />
          {/**TODO: i18n*/}
          <Text t="text.go_back" bold />
        </BackLink>
        <div className="flex-1" />
        <Button variant={"accent"} onClick={() => toPdf()}>
          Export
        </Button>
      </header>
      <div ref={$pdf} className="grid grid-cols-3 gap-2.5">
        <DashboardTrendDataDetails data={trendData} loading={trendLoading} queryParams={query} />
        <DashboardDetailMarketStream query={{ ...query, startDate: undefined, endDate: undefined }} />
        <DashboardDetailOverview
          loading={loading}
          data={data}
          queryParams={query}
          setQueryParams={setQuery}
          trendData={trendData}
        />
        <DashboardDetailMarketLandscape queryParams={query} />
      </div>
    </div>
  )
}

