function PinterestPost() {
  const { id } = useParams()
  const [searchParams] = useSearchParams()
  const pinnerId = searchParams.get("pinnerId")
  const { data: pinner = {}, loading } = useRequest(() => servicePinterestUserDetail({ pinterestUserId: pinnerId || "" }), {
    refreshDeps: [pinnerId],
  })
  const { data: postDetail = {} } = useRequest(() => servicePinterestBlogDetail({ pinId: id }), { refreshDeps: [id] })
  const { data } = useImageList()
  const { pre, next } = useMemo(() => {
    const postList: PinterestBlogVo[] = (data as PinterestBlogVo[]) || []
    const currentIndex = postList.findIndex((m) => m.pinId === id)
    const pre = currentIndex > 0 ? postList[currentIndex - 1] : {}
    const next = currentIndex < postList.length - 1 ? postList[currentIndex + 1] : {}
    return { pre, next }
  }, [data, id])

  const { addBrowsingHistory } = useBrowsingHistory()
  useEffect(() => {
    window.scrollTo(0, 0)
    addBrowsingHistory({ entityId: id, entityType: "PINTEREST_BLOG" })
  }, [id])
  return (
    <RecoilRoot>
      <PinterestPostContext.Provider value={{ pinner, postDetail, images: postDetail?.images || [], loading }}>
        <div className="mb-3">
          <GoBack />
        </div>
        <Panel.Root className="pt-3">
          <Panel.Content className="relative">
            <Outlet />
            {!loading && <Link pre={pre} next={next} />}
          </Panel.Content>
        </Panel.Root>
      </PinterestPostContext.Provider>
    </RecoilRoot>
  )
}

