getRows = (type: GroupByType, data: InternalStatisticsCellVo[], sheetName: string) => {
    const columns = getColumns(type).map((m) => ({ ...m, header: m.title }))
    const rowData =
      data?.map((m, index) => {
        const row = columns.map((col) => {
          const value = renderValue(m, col.dataIndex, index)
          return value
        })
        return row
      }) || []
    return {
      sheetName,
      columns,
      rowData,
    }
  }

interface Column {
  title: string
  dataIndex: string
  tip?: string
}

getColumns = (type: GroupByType): Column[] => {
  const columnConfig: Partial<Record<GroupByType, Column>> = {
    BRAND: { title: "Brand", dataIndex: "groupName" },
    FAMILY: { title: "Family", dataIndex: "groupName" },
    PRODUCT_TYPE: { title: "Product Type", dataIndex: "groupName" },
    CAT1: { title: "Gender", dataIndex: "groupName" },
    CAT2: { title: "Category Group", dataIndex: "groupName" },
    CAT3: { title: "Category", dataIndex: "groupName" },
  }
  if (!columnConfig[type]) {
    throw new Error(`Invalid GroupByType: ${type}`)
  }
  return [
    { title: "", dataIndex: "rank" },
    columnConfig[type],
    { title: "Volume (Qty)", dataIndex: "total" },
    { title: "% Growth", dataIndex: "growth" },
    // {
    //   title: "LF Proportion",
    //   dataIndex: "proportion",
    //   tip: "This table value and chart show “Rolling 12 months” or “ Rolling 6 months” based on the time selection",
    // },
  ]
}

renderValue = (m: InternalStatisticsCellVo, dataIndex: string, index: number) => {
  if (dataIndex === "groupName") {
    return m[dataIndex]
  }
  if (dataIndex === "rank") return `#${index + 1}`
  if (dataIndex === "total") return m[dataIndex] ? m[dataIndex].toLocaleString() : "-"
  if (["proportion", "growth"].includes(dataIndex)) {
    return m[dataIndex] ? formatPercent(m[dataIndex]) : "-"
  }
  return m[dataIndex] || "-"
}

