function convertStartAndEndDate(startAndEndDate?: [string, string, string]) {
  if (!startAndEndDate || startAndEndDate.filter(Boolean).length !== 3) return {}
  return { ...convertStartAndEnd("Date", convertBaseDateWithDiff(startAndEndDate.join(","))) }
