interface Tabs {
  label: string
  path: string
  isEnd?: boolean
}

function AnalysisStatistics() {
  const navigate = useNavigate()
  const location = useLocation()
  const [total] = useMarketAnalysisTotalState()
  const [queryParams, setQueryParams] = useMarketAnalysisParams()
  const [, setSearchTrigger] = useMarketAnalysisSearchTrigger()

  const onParamsChange = (_params: SetStateAction<MarketAnalysisParams>) => {
    setQueryParams((prev) => ({ ...prev, ..._params }))
  }

  const isApparelIndustry = queryParams.industry === APPAREL_ID
  const isValidIndustry = [APPAREL_ID, FOOTWEAR_ID].includes(queryParams.industry!)

  const tabs = useMemo<Tabs[]>(() => {
    const tabsConfig = [
      // { label: "field.product_category", path: "product-category", isEnd: true },
      isApparelIndustry && { label: "field.product_assortment", path: "product-assortment" },
      isValidIndustry && { label: "field.raw_material", path: "raw-material" },
      isApparelIndustry && { label: "field.colors", path: "colors" },
      isApparelIndustry && { label: "field.pattern", path: "pattern" },
      isValidIndustry && { label: "field.detail", path: "detail" },
      { label: "field.price", path: "price" },
    ]

    return tabsConfig.filter(Boolean) as Tabs[]
  }, [isApparelIndustry, isValidIndustry])

  useEffect(() => {
    const currentPath = location.pathname
    const isValidPath = tabs.some((tab) => !tab.isEnd && currentPath.endsWith(tab.path))

    if (!isValidPath) {
      navigate(tabs[0].path)
    }
  }, [location.pathname, tabs, navigate])

  return (
    <>
      <div className="mb-3 mt-8">
        <div className="pb-3 text-lg font-bold">
          {t("text.search_result")}{" "}
          {total && import.meta.env.VITE_MARKET_RESULT_COUNT !== "false" ? `(${total.toLocaleString()})` : ""}
        </div>
        <ListSearchTextbox
          value={queryParams.text || ""}
          onValueChange={(text) => {
            onParamsChange({ text })
            setSearchTrigger((pre) => !pre)
          }}
          className="h-10 w-80 rounded-none bg-background px-2"
          placeholder="Search products by name"
        ></ListSearchTextbox>
      </div>
      <Panel.Root className="mt-2.5">
        <NavTabs className="border-b px-8">
          {tabs.map((tab) => (
            <NavTabItem key={tab.path} to={tab.path} end={tab.isEnd}>
              <Text t={tab.label} />
            </NavTabItem>
          ))}
        </NavTabs>
        <Outlet />
      </Panel.Root>
    </>
  )
}

