interface Tabs {
  label: string
  path: string
  isEnd?: boolean
}

function RunwayAnalysisStatistics() {
  const [params] = useRunwayAnalysisParams()
  const navigate = useNavigate()
  const location = useLocation()
  const isApparelIndustry = params.industry === APPAREL_ID
  const tabs = useMemo<Tabs[]>(() => {
    const tabsConfig = [
      { label: "text.category", path: "category", isEnd: true },
      { label: "field.material", path: "material" },
      isApparelIndustry && { label: "field.colors", path: "colors" },
      isApparelIndustry && { label: "field.pattern", path: "pattern" },
      { label: "field.detail", path: "detail" },
    ]

    return tabsConfig.filter(Boolean) as Tabs[]
  }, [isApparelIndustry])

  useEffect(() => {
    const currentPath = location.pathname
    const isValidPath = tabs.some((tab) => !tab.isEnd && currentPath.endsWith(tab.path))

    if (!isValidPath) {
      navigate(tabs[0].path)
    }
  }, [location.pathname, tabs, navigate])

  return (
    <div>
      <RunwayAnalysisFilter />
      <Panel.Root>
        <NavTabs className="border-b px-8">
          {tabs.map((tab) => (
            <NavTabItem key={tab.path} to={tab.path} end={tab.isEnd}>
              <Text t={tab.label} />
            </NavTabItem>
          ))}
        </NavTabs>
        <Outlet />
      </Panel.Root>
    </div>
  )
}

