function useFilterOptions() {
  const {
    data: brandOptions = [],
    loading: brandLoading,
    run: brandReload,
    mutate,
  } = useRequest(
    async (keyword: string = "") => {
      const res = (await serviceFashionOptionBrand({ type: "CLOTHES", keyword })) as BackEndOption[]
      return res.map(transformOptions) ?? []
    },
    {
      debounceTrailing: true,
      debounceWait: 500,
      onBefore: () => {
        mutate([])
      },
    },
  )

  const { data: seasonOptions = [] } = useRequest(async () => {
    const res = (await serviceFashionOptionSeason({ type: "RUNWAY" })) as BackEndOption[]
    return res.map(transformOptions)
  })

  const { data: regionOptions = [] } = useRequest(async () => {
    const res = (await serviceFashionOptionRegion({ type: "RUNWAY" })) as BackEndOption[]
    return res.map(transformOptions)
  })

  const { data: colorOptions = [] } = useRequest(async () => {
    const res = (await serviceFashionOptionColor({ type: "RECOGNITION" })) as BackEndOption[]
    return res.map(transformOptions)
  })

  const { data: styleOptions = [] } = useRequest(async () => {
    const res = (await serviceFashionOptionStyle({ type: "RECOGNITION" })) as BackEndOption[]
    return res.map(transformOptions)
  })

  const { data: categoryOptions = [] } = useRequest(async () => {
    const res = (await serviceFashionOptionCategory({ type: "RECOGNITION" })) as BackEndOption[]
    return res.map(transformOptions)
  })

  const { data: elementOptions = [] } = useRequest(async () => {
    const res = await serviceFashionOptionDesignLabel()
    return res as Option[]
  })

  const { data: brandStyleOptions = [] } = useRequest(async () => {
    const res = (await serviceFashionOptionBrandStyle({ type: "RUNWAY" })) as BackEndOption[]
    return res.map(transformOptions)
  })

  const { data: brandTypeOptions = [] } = useRequest(async () => {
    const res = (await serviceFashionOptionBrandType({ type: "RUNWAY" })) as BackEndOption[]
    return res.map(transformOptions)
  })

  return {
    brandTypeOptions,
    brandStyleOptions,
    elementOptions,
    brandOptions,
    brandReload,
    brandLoading,
    seasonOptions,
    regionOptions,
    colorOptions,
    styleOptions,
