function Setting() {
  const [inviteOpen, setInviteOpen] = useState(false)
  const permissions = usePermissions()
  const userRoles = useRoles()
  const isRoot = permissions?.functionPermissions?.includes("role_config")
  const adminRoles = userRoles?.roles?.filter((p) => p.isAdmin) || []

  const { data: roles = [], refresh, mutate } = useRequest(serviceAuthorityRoles)

  const handleInviteConfirm = () => {
    setInviteOpen(false)
    refresh()
    window.dispatchEvent(new Event(REFRESH_EVENT))
  }

  return (
    <div className="flex flex-col gap-3">
      <Panel.Root className="pb-0">
        <div className="flex pr-7.5">
          <Panel.Title className="flex items-center">
            <SettingIcon size={24} />
            <span className="ml-2 uppercase">Setting</span>
          </Panel.Title>
          <Button variant="accent" onClick={() => setInviteOpen(true)}>
            <CloseIcon size={24} className="rotate-45 mr-2" />
            <Text t="setting.invite_users" />
          </Button>
        </div>
        <Panel.Content>
          <div className="mb-5 mt-2 text-sm">Easily add users, manage access, and configuration</div>
          <NavTabs>
            {TABS.map((tab) => (
              <NavTabItem key={tab.pathname} to={tab.pathname} replace>
                {tab.label}
              </NavTabItem>
            ))}
          </NavTabs>
        </Panel.Content>
      </Panel.Root>
      <InviteUser open={inviteOpen} setOpen={setInviteOpen} roles={isRoot ? roles : adminRoles} onConfirm={handleInviteConfirm} />
      <Outlet
        context={{
          refreshRoles: refresh,
          setRoles: mutate,
          roles: isRoot ? roles : adminRoles,
          isRoot,
          currentRoles: userRoles?.roles,
          currentUserId: userRoles?.userId,
          refreshEvent: REFRESH_EVENT,
        }}
      />
    </div>
  )
}

