  const defaultParams = useDefaultWhitespaceParams({
    trendCategory: query.trendCategory as string[][],
    retailer: query.platformType as string,
    industry: query.industry as string,
  })
  const [params, setParams] = useRecoilState(whitespaceParams)
  const analysisParams = useMemo(() => {
    return {
      sortType: SORT_OPTIONS_TYPES.newArrivals,
      ...(defaultParams || {}),
      ...query,
      trendCategory: undefined,
      platformType: undefined,
      ...params,
    }
  }, [query, params, defaultParams])

  return [analysisParams, setParams] as const
}

function useWhitespaceTotalState() {
  const [total, setTotal] = useRecoilState(whitespaceTotal)
  useEffect(() => {
    setTotal(0)
  }, [])
  return [total, setTotal] as const
}

function convertStartAndEndDate(startAndEndDate?: [string, string, string]) {
  if (!startAndEndDate || startAndEndDate.filter(Boolean).length !== 3) return {}
  return { ...convertStartAndEnd("Date", convertBaseDateWithDiff(startAndEndDate.join(","))) }
}

function convertWhitespaceParams(params: { [key: string]: unknown }) {
  const { startDate, endDate } = convertStartAndEndDate(params.onSaleDate as [string, string, string])
  return {
    ...params,
    categoryIdList: convertIndustryCategories({ industry: params.industry, categories: params.categoryIdList } as {
      industry?: string
      categories?: string[][]
    }),
    startDate,
    endDate,
    metaFlagList: [params.metaAd, params.publicPage, params.facebookCarousel].filter(Boolean),
    platformTypeList: (params.retailers as string[][])?.map((m: string[]) => m.at(-1)),
    productAssortment: (params.productAssortment as string[])?.map((m) => [m]),
    color: (params.color as string[][])?.map((m: string[]) => m.at(-1)),
    minOutOfStockRate: params.outOfStockRate,
  }
}

function convertCategory(category?: string[][]) {
  if (!category?.length) {
    return {}
  }

  const firstIds = new Set<string>()
  const secondIds = new Set<string>()
  const thirdIds: string[] = []

  category.forEach((item) => {
    if (item[0]) firstIds.add(item[0])
    if (item[1]) secondIds.add(item[1])
    if (item[2]) thirdIds.push(item[2])
  })

  return {
    firstCategoryIdList: Array.from(firstIds),
    secondCategoryIdList: Array.from(secondIds),
    thirdCategoryIdList: thirdIds,
  }
}

useKeywords = (params: { [key: string]: unknown }) => {
  return useRecoilValue(getKeywords(params))
}

